  1→using System;
  2→using System.Drawing;
  3→using System.Linq;
  4→using System.Windows.Forms;
  5→
  6→namespace NoiseTest
  7→{
  8→    /// <summary>
  9→    /// IO 모니터 폼 — IN/OUT 각 32채널
 10→    /// 레이아웃: IN00-15 | IN16-31 | OUT00-15 | OUT16-31 (16행 × 4열)
 11→    /// 폼: 820 × 681
 12→    /// </summary>
 13→    public partial class FrmIO : Form
 14→    {
 15→        private const int CH   = 32;
 16→        private const int ROWS = 16;
 17→
 18→        private PictureBox[] _inPics  = new PictureBox[CH];
 19→        private PictureBox[] _outPics = new PictureBox[CH];
 20→        private Label[]      _inLbls  = new Label[CH];
 21→        private Label[]      _outLbls = new Label[CH];
 22→
 23→        private bool _updating = false;
 24→
 25→        public FrmIO()
 26→        {
 27→            InitializeComponent();
 28→            CreateIoControls();
 29→            SetupIOLabels();
 30→
 31→            timer1.Interval = 100;
 32→            timer1.Tick += timer1_Tick;
 33→            timer1.Start();
 34→        }
 35→
 36→        // ===== 동적 컨트롤 생성 =====
 37→
 38→        private void CreateIoControls()
 39→        {
 40→            const int PB_W    = 58;
 41→            const int PB_H    = 50;
 42→            const int LBL_H   = 40;
 43→            const int Y_START = 22;   // 헤더 아래
 44→            const int Y_STEP  = 57;   // 16행 × 57 = 912, 1080p 화면에 전체 수용
 45→
 46→            // 열 좌표 (폼 너비 1100px, 컬럼 너비 200px)
 47→            const int C1_PB  =   6;  const int C1_LBL =  70; const int C1_W = 200;  // IN00-15
 48→            const int C2_PB  = 278;  const int C2_LBL = 342; const int C2_W = 200;  // IN16-31
 49→            const int C3_PB  = 554;  const int C3_LBL = 618; const int C3_W = 200;  // OUT00-15
 50→            const int C4_PB  = 826;  const int C4_LBL = 890; const int C4_W = 200;  // OUT16-31
 51→
 52→            for (int row = 0; row < ROWS; row++)
 53→            {
 54→                int y   = Y_START + row * Y_STEP;
 55→                int in0 = row;       // IN00-15
 56→                int in1 = row + 16;  // IN16-31
 57→                int ou0 = row;       // OUT00-15
 58→                int ou1 = row + 16;  // OUT16-31
 59→
 60→                CreateIn (in0, y, C1_PB, C1_LBL, C1_W, PB_W, PB_H, LBL_H);
 61→                CreateIn (in1, y, C2_PB, C2_LBL, C2_W, PB_W, PB_H, LBL_H);
 62→                CreateOut(ou0, y, C3_PB, C3_LBL, C3_W, PB_W, PB_H, LBL_H);
 63→                CreateOut(ou1, y, C4_PB, C4_LBL, C4_W, PB_W, PB_H, LBL_H);
 64→            }
 65→
 66→            // IN/OUT 구분선 (C2 끝 ~ C3 사이)
 67→            panel3.Controls.Add(new Label
 68→            {
 69→                Location  = new Point(544, 0),
 70→                Size      = new Size(4, panel3.Height),
 71→                BackColor = Color.DimGray,
 72→                Text      = ""
 73→            });
 74→
 75→            // 컬럼 헤더
 76→            AddHeader("INPUT  (IN00~IN31)",   6,   3, 534);
 77→            AddHeader("OUTPUT (OUT00~OUT31)", 552,  3, 540);
 78→        }
 79→
 80→        private void CreateIn(int i, int y, int pbX, int lblX, int lblW,
 81→                               int pbW, int pbH, int lblH)
 82→        {
 83→            var pic = new PictureBox
 84→            {
 85→                Size = new Size(pbW, pbH), Location = new Point(pbX, y),
 86→                BackColor = Color.Black,   Name = $"picIn{i}"
 87→            };
 88→            MakeCircle(pic);
 89→            AddOverlayLabel(pic, $"IN{i:D2}");
 90→            panel3.Controls.Add(pic);
 91→            _inPics[i] = pic;
 92→
 93→            var lbl = new Label
 94→            {
 95→                Size = new Size(lblW, lblH), Location = new Point(lblX, y + 4),
 96→                Text = $"IN{i:D2}", TextAlign = ContentAlignment.MiddleLeft,
 97→                Font = new Font("Segoe UI", 8), Name = $"lblIn{i}"
 98→            };
 99→            panel3.Controls.Add(lbl);
100→            _inLbls[i] = lbl;
101→        }
102→
103→        private void CreateOut(int i, int y, int pbX, int lblX, int lblW,
104→                                int pbW, int pbH, int lblH)
105→        {
106→            var pic = new PictureBox
107→            {
108→                Size = new Size(pbW, pbH), Location = new Point(pbX, y),
109→                BackColor = Color.Black,   Name = $"picOut{i}", Tag = i
110→            };
111→            MakeCircle(pic);
112→            AddOverlayLabel(pic, $"OUT{i:D2}");
113→            pic.Click += pictureBoxOutput_Click;
114→            var ol = GetOverlayLabel(pic);
115→            if (ol != null) { var cap = pic; ol.Click += (s, e) => pictureBoxOutput_Click(cap, EventArgs.Empty); }
116→            panel3.Controls.Add(pic);
117→            _outPics[i] = pic;
118→
119→            var lbl = new Label
120→            {
121→                Size = new Size(lblW, lblH), Location = new Point(lblX, y + 4),
122→                Text = $"OUT{i:D2}", TextAlign = ContentAlignment.MiddleLeft,
123→                Font = new Font("Segoe UI", 8), Name = $"lblOut{i}"
124→            };
125→            panel3.Controls.Add(lbl);
126→            _outLbls[i] = lbl;
127→        }
128→
129→        private void AddHeader(string text, int x, int y, int width)
130→        {
131→            panel3.Controls.Add(new Label
132→            {
133→                Location = new Point(x, y), Size = new Size(width, 16),
134→                Text = text, Font = new Font("Segoe UI", 8, FontStyle.Bold),
135→                ForeColor = Color.DimGray, TextAlign = ContentAlignment.MiddleLeft
136→            });
137→        }
138→
139→        // ===== IO 역할명 =====
140→
141→        private void SetupIOLabels()
142→        {
143→            string[] inputNames = new string[]
144→            {
145→                "시작 버튼",        // IN00
146→                "리셋 스위치",      // IN01
147→                "비상정지(B접)",    // IN02
148→                "클램프 센서",      // IN03
149→                "언클램프 센서",    // IN04
150→                "검사위치 센서",    // IN05
151→                "원위치 센서",      // IN06
152→                "웨이트 하강 센서", // IN07
153→                "웨이트 상승 센서", // IN08
154→                "전진센서",         // IN09
155→                "하강",             // IN10
156→                "상승",             // IN11
157→                "-",                // IN12
158→                "게이지 전진 센서", // IN13
159→                "게이지 후진 센서", // IN14
160→                "웨이트고정 후진1", // IN15
161→                "웨이트고정 전진1", // IN16
162→                "웨이트고정 전진2", // IN17
163→                "웨이트고정 후진2", // IN18
164→                "-",                // IN19
165→                "-",                // IN20
166→                "-",                // IN21
167→                "통전 검출",        // IN22
168→                "각도기 감지1",     // IN23
169→                "각도기 감지2",     // IN24
170→                "-",                // IN25
171→                "-",                // IN26
172→                "-",                // IN27
173→                "-",                // IN28
174→                "-",                // IN29
175→                "-",                // IN30
176→                "-"                 // IN31
177→            };
178→
179→            string[] outputNames = new string[]
180→            {
181→                "클램프",           // OUT00
182→                "언클램프",         // OUT01
183→                "검사위치 이동",    // OUT02
184→                "원위치 이동",      // OUT03
185→                "웨이트 하강",      // OUT04
186→                "웨이트 상승",      // OUT05
187→                "-",                // OUT06
188→                "-",                // OUT07
189→                "-",                // OUT08
190→                "-",                // OUT09
191→                "게이지 전진",      // OUT10
192→                "게이지 후진",      // OUT11
193→                "웨이트고정 전진1", // OUT12
194→                "웨이트고정 후진1", // OUT13
195→                "웨이트고정 전진2", // OUT14
196→                "웨이트고정 후진2", // OUT15
197→                "-",                // OUT16
198→                "-",                // OUT17
199→                "-",                // OUT18
200→                "-",                // OUT19
201→                "-",                // OUT20
202→                "-",                // OUT21
203→                "-",                // OUT22
204→                "-",                // OUT23
205→                "CW 동작",          // OUT24
206→                "CCW 동작",         // OUT25
207→                "원형고정",         // OUT26
208→                "원형해제",         // OUT27
