212→                "후진"              // OUT31
213→            };
214→
215→            for (int i = 0; i < CH; i++)
216→            {
217→                if (_inLbls[i]  != null) _inLbls[i].Text  = $"IN{i:D2}  {inputNames[i]}";
218→                if (_outLbls[i] != null) _outLbls[i].Text = $"OUT{i:D2} {outputNames[i]}";
219→            }
220→        }
