222→        // ===== UI 헬퍼 =====
223→
224→        private void MakeCircle(PictureBox pic)
225→        {
226→            var gp = new System.Drawing.Drawing2D.GraphicsPath();
227→            gp.AddEllipse(0, 0, pic.Width - 1, pic.Height - 1);
228→            pic.Region = new Region(gp);
229→        }
230→
231→        private void AddOverlayLabel(PictureBox pic, string text)
232→        {
233→            var old = GetOverlayLabel(pic);
234→            if (old != null) pic.Controls.Remove(old);
235→            pic.Controls.Add(new Label
236→            {
237→                Text = text, AutoSize = false,
238→                TextAlign = ContentAlignment.MiddleCenter, Dock = DockStyle.Fill,
239→                BackColor = Color.White, ForeColor = Color.Black,
240→                Font = new Font("Segoe UI", 7, FontStyle.Bold), Name = "OverlayLabel"
241→            });
242→        }
243→
244→        private static Label GetOverlayLabel(PictureBox pic)
245→            => pic?.Controls.OfType<Label>().FirstOrDefault(l => l.Name == "OverlayLabel");
246→
247→        private void ApplyOnOffStyle(PictureBox pic, bool isOn)
248→        {
249→            if (pic == null) return;
250→            pic.BackColor = isOn ? Color.Blue : Color.Black;
251→            var lbl = GetOverlayLabel(pic);
252→            if (lbl != null)
253→            {
254→                lbl.BackColor = isOn ? Color.Black : Color.White;
255→                lbl.ForeColor = isOn ? Color.White : Color.Black;
256→            }
257→        }
258→
259→        // ===== 출력 토글 클릭 =====
260→
261→        private void pictureBoxOutput_Click(object sender, EventArgs e)
262→        {
263→            var pic = sender as PictureBox;
264→            if (pic == null || FrmMain.io == null) return;
265→
266→            int index = -1;
267→            if (pic.Tag is int i) index = i;
268→            else if (!int.TryParse(pic.Tag + "", out index)) return;
269→            if (index < 0 || index >= CH) return;
270→
271→            bool next = !FrmMain.io.GetOutput(index);
272→            if (next) { FrmMain.io.Do_On_Force(index);  FrmMain.io.Commit(); }
273→            else      { FrmMain.io.Do_Off_Force(index); FrmMain.io.Commit(); }
274→
275→            ApplyOnOffStyle(pic, next);
276→        }
277→
278→        // ===== 주기 갱신 =====
279→
280→        private void timer1_Tick(object sender, EventArgs e)
281→        {
282→            if (_updating) return;
283→            _updating = true;
284→            try
