                Location  = new Point(544, 0),
                Size      = new Size(4, panel3.Height),
                BackColor = Color.DimGray,
                Text      = ""
            });

            // 컬럼 헤더
            AddHeader("INPUT  (IN00~IN31)",   6,   3, 534);
            AddHeader("OUTPUT (OUT00~OUT31)", 552,  3, 540);
        }

